+/// _PyLong_Copy - Copy a long object
+pub export fn _PyLong_Copy(obj: *cpython.PyObject) callconv(.c) ?*cpython.PyObject {
+    const pylong = @import("../objects/longobject.zig");
+    if (pylong.PyLong_Check(obj) == 0) return null;
